"use strict";(self.webpackChunkredux_box=self.webpackChunkredux_box||[]).push([[563],{5290(n,s,a){a.r(s),a.d(s,{_pageData:()=>e,default:()=>o});var t=a(641);const e=JSON.parse('{"path":"/api/utils/get.html","title":"get","lang":"en-US","frontmatter":{"title":"get"},"git":{"updatedTime":1778312827000,"contributors":[{"name":"Anish Kumar","username":"","email":"anish000kumar@gmail.com","commits":1}],"changelog":[{"hash":"594d62902ab92e6dc03bcfce4fa066d20824da61","time":1778312827000,"email":"anish000kumar@gmail.com","author":"Anish Kumar","message":"coveralls upgraded and docs polish"}]},"filePathRelative":"api/utils/get.md"}'),p={name:"get.md"},o=(0,a(6262).A)(p,[["render",function(n,s,a,e,p,o){return(0,t.uX)(),(0,t.CE)("div",null,[...s[0]||(s[0]=[(0,t.Fv)('<h1 id="get" tabindex="-1"><a class="header-anchor" href="#get"><span>get</span></a></h1><p><a name="get"></a></p><h2 id="get-object-keys-defaultval-⇒" tabindex="-1"><a class="header-anchor" href="#get-object-keys-defaultval-⇒"><span>get(object, keys, [defaultVal]) ⇒ <code>*</code></span></a></h2><p>Safely reads a deeply nested value from an object using a dot-separated path (or an array of keys). If any segment of the path is missing, <code>defaultVal</code> is returned instead of throwing.</p><p><strong>Kind</strong>: global function<br><strong>Returns</strong>: <code>*</code> - The resolved value, or <code>defaultVal</code> if the path could not be resolved.</p><table><thead><tr><th>Param</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>object</td><td><code>Object</code></td><td>Source object to read from. Non-objects return <code>defaultVal</code>.</td></tr><tr><td>keys</td><td><code>String</code> | <code>Array.&lt;String&gt;</code></td><td>Dot-separated path (e.g. <code>&quot;a.b.c&quot;</code>) or an array of keys.</td></tr><tr><td>[defaultVal]</td><td><code>*</code></td><td>Value returned when the path resolves to <code>undefined</code>.</td></tr></tbody></table><p><strong>Example</strong></p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">import</span> <span class="token keyword">get</span> <span class="token keyword">from</span> <span class="token string">&#39;redux-box/dist/utils/get&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"></span>\n<span class="line"><span class="token keyword">const</span> state <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">user</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">profile</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;Anish&#39;</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">;</span></span>\n<span class="line"></span>\n<span class="line"><span class="token function">get</span><span class="token punctuation">(</span>state<span class="token punctuation">,</span> <span class="token string">&#39;user.profile.name&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>           <span class="token comment">// =&gt; &#39;Anish&#39;</span></span>\n<span class="line"><span class="token function">get</span><span class="token punctuation">(</span>state<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;profile&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;name&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>   <span class="token comment">// =&gt; &#39;Anish&#39;</span></span>\n<span class="line"><span class="token function">get</span><span class="token punctuation">(</span>state<span class="token punctuation">,</span> <span class="token string">&#39;user.profile.age&#39;</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>         <span class="token comment">// =&gt; 0 (missing key, default returned)</span></span>\n<span class="line"><span class="token function">get</span><span class="token punctuation">(</span>state<span class="token punctuation">,</span> <span class="token string">&#39;user.address.city&#39;</span><span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">// =&gt; null</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',8)])])}]])}}]);